import{_ as s,o as a,c as t,ag as n}from"./chunks/framework.DAvaMl8U.js";const u=JSON.parse('{"title":"Search","description":"","frontmatter":{},"headers":[],"relativePath":"search.md","filePath":"search.md"}'),i={name:"search.md"};function o(c,e,r,d,l,h){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h1><p>Search is implemented in <code>backend/src/services/search-service.ts</code> using SQL builders from <code>backend/src/sql/search.ts</code>.</p><h2 id="strategy" tabindex="-1">Strategy <a class="header-anchor" href="#strategy" aria-label="Permalink to &quot;Strategy&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>query received</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ▼</span></span>
<span class="line"><span>websearch_to_tsquery() produces empty string?</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>    yes ──► return { total: 0, results: [] }   (stop words, e.g. &quot;the&quot;)</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>    no</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ▼</span></span>
<span class="line"><span> ftSearch()          ← search_vector @@ tsq, ts_rank_cd, time decay (GIN index)</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>  total &gt; 0? ──yes──► return FTS results</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>    no</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ▼</span></span>
<span class="line"><span> fuzzySearch()       ← similarity(title, q) &gt; 0.1  (GIN trgm index on title)</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ▼</span></span>
<span class="line"><span> return fuzzy results</span></span></code></pre></div><p>FTS is always tried first. Fuzzy search only runs if FTS finds nothing.</p><hr><h2 id="stop-word-short-circuit" tabindex="-1">Stop word short-circuit <a class="header-anchor" href="#stop-word-short-circuit" aria-label="Permalink to &quot;Stop word short-circuit&quot;">​</a></h2><p>Before running any database query, <code>search-service.ts</code> checks whether <code>websearch_to_tsquery(&#39;english&#39;, q)</code> produces an empty tsquery:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (websearch_to_tsquery(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;english&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)::</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">text</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> is_empty</span></span></code></pre></div><p>If <code>is_empty</code> is true (common English stop words like &quot;the&quot;, &quot;a&quot;, &quot;is&quot;), the service returns an empty result immediately without hitting the main search tables. This prevents a very slow full fuzzy scan that would otherwise be triggered as a fallback.</p><hr><h2 id="full-text-search-fts" tabindex="-1">Full-text search (FTS) <a class="header-anchor" href="#full-text-search-fts" aria-label="Permalink to &quot;Full-text search (FTS)&quot;">​</a></h2><p><strong>SQL builder</strong>: <code>buildFtsQuery(whereClause, limitParam, offsetParam)</code></p><h3 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><ol><li>The query is parsed with <code>websearch_to_tsquery(&#39;english&#39;, $2)</code> — supports natural language syntax: <code>&quot;product roadmap&quot; NOT finance</code>, <code>roadmap OR milestone</code>.</li><li>The LATERAL join pre-filters <code>document_chunks</code> by <code>dc.search_vector @@ tsq.q</code> (uses the GIN index <code>ix_chunks_search_vector</code>) before ranking, so only matching chunks are considered.</li><li>A combined tsvector is constructed: <ul><li>Title → weighted <code>&#39;A&#39;</code> (highest)</li><li>Best matching chunk content → weighted <code>&#39;B&#39;</code></li></ul></li><li>Documents are filtered by <code>d.search_vector @@ tsq.q</code> (uses <code>ix_documents_search_vector</code> GIN index).</li><li><strong>Score</strong> = <code>ts_rank_cd(sv, q, 32) × time_decay</code><ul><li><code>ts_rank_cd</code> uses cover density ranking (penalises scattered term matches)</li><li>Time decay: <code>exp(−age_seconds / (90 days × 86400))</code> — a 90-day half-life so recent documents score higher for equal relevance</li></ul></li><li><strong>Snippet</strong> is generated with <code>ts_headline()</code> using <code>&lt;&lt;</code> / <code>&gt;&gt;</code> delimiters (rendered as highlighted text in the UI). Input is capped at 5KB to prevent slow headline generation on large documents.</li></ol><h3 id="count-query" tabindex="-1">Count query <a class="header-anchor" href="#count-query" aria-label="Permalink to &quot;Count query&quot;">​</a></h3><p><code>buildFtsCountQuery(whereClause)</code> runs a lighter query (no ranking, no headline) that counts matching documents. Run in parallel with the main query via <code>Promise.all</code>.</p><hr><h2 id="fuzzy-search" tabindex="-1">Fuzzy search <a class="header-anchor" href="#fuzzy-search" aria-label="Permalink to &quot;Fuzzy search&quot;">​</a></h2><p><strong>SQL builder</strong>: <code>buildFuzzyQuery(whereClause, limitParam, offsetParam)</code></p><h3 id="how-it-works-1" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works-1" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><p>Uses the <code>pg_trgm</code> extension&#39;s <code>similarity()</code> function on <strong>document titles only</strong>:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">similarity(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">d</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> raw_score</span></span></code></pre></div><p>Only documents where the title similarity exceeds <code>0.1</code> are included. This uses the <code>ix_documents_title_trgm</code> GIN index and remains fast at scale.</p><blockquote><p><strong>Note</strong>: Fuzzy search does not scan chunk content. Scanning chunk content inside a subquery cannot use a GIN index and would be extremely slow on large datasets. Title-only fuzzy catches the most common case (typos/partial matches in document names).</p></blockquote><p>Score threshold of 0.1 keeps noise out while still catching partial matches and typos (e.g. <code>roadmap</code> vs <code>roadmpa</code>).</p><p>Snippet is the raw title — no <code>ts_headline</code> in fuzzy mode.</p><hr><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><p>Both FTS and fuzzy share the same filter builder (<code>buildFilters()</code> in <code>search-service.ts</code>):</p><table tabindex="0"><thead><tr><th>Filter</th><th>SQL</th></tr></thead><tbody><tr><td><code>orgId</code></td><td><code>d.org_id = $1</code> (always applied)</td></tr><tr><td><code>connectorId</code></td><td><code>d.connector_id = $N</code></td></tr><tr><td><code>kind</code></td><td><code>d.kind = $N</code></td></tr><tr><td><code>fromDate</code></td><td><code>d.mtime &gt;= $N</code></td></tr><tr><td><code>toDate</code></td><td><code>d.mtime &lt;= $N</code></td></tr></tbody></table><p>The WHERE clause string and the <code>values[]</code> array are passed into the builder functions so the SQL stays parameterised.</p><hr><h2 id="pagination" tabindex="-1">Pagination <a class="header-anchor" href="#pagination" aria-label="Permalink to &quot;Pagination&quot;">​</a></h2><p>Both search modes support <code>limit</code> / <code>offset</code>. Defaults: <code>limit=20</code>, <code>offset=0</code>. The response includes <code>total</code> (exact count) for UI pagination (20 results per page in the frontend).</p><hr><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/v1/orgs/:slug/search?q=&lt;query&gt;[&amp;connector_id=…][&amp;kind=…][&amp;date_from=…][&amp;date_to=…][&amp;limit=…][&amp;offset=…]</span></span></code></pre></div><p>See <code>docs/api.md</code> for the full response shape.</p><hr><h2 id="search-vector-maintenance" tabindex="-1">Search vector maintenance <a class="header-anchor" href="#search-vector-maintenance" aria-label="Permalink to &quot;Search vector maintenance&quot;">​</a></h2><p><code>search_vector</code> columns on <code>documents</code> and <code>document_chunks</code> are populated during indexing, not at query time:</p><ul><li><code>documents.search_vector</code> is updated after each upsert via a dedicated SQL statement: <code>to_tsvector(&#39;english&#39;, coalesce(title, &#39;&#39;))</code>.</li><li><code>document_chunks.search_vector</code> is set on chunk insert: <code>to_tsvector(&#39;english&#39;, content)</code>.</li></ul><p>Both columns are indexed with GIN indexes (<code>ix_documents_search_vector</code>, <code>ix_chunks_search_vector</code>), keeping queries fast — no runtime <code>to_tsvector()</code> calls at query time.</p>`,44)])])}const g=s(i,[["render",o]]);export{u as __pageData,g as default};
